name                                  fcs       /RESCUE/

* Genesis!

* start: bootstrap OS-9 resources and load every game asset.
start                                 equ       *
* install our signal handler
                                      leax      >sighand,pcr                              ; advance/derive X so it addresses a field in the PCR-indexed structure for the next game control flow item.
                                      ldu       #saved_blit_x                             ; seed U with constant saved_blit_x for the upcoming game control flow operation.
                                      os9       F$Icpt                                    ; ask OS-9 to install the signal interceptor.
                                      orcc      #IntMasks                                 ; change only the condition-code bits required to make the following game control flow operation atomic/correct.
                                      lds       #ws_boot_buffer_25+$2657                  ; seed S with constant ws_boot_buffer_25+$2657 for the upcoming game control flow operation.
                                      andcc     #^IntMasks                                ; change only the condition-code bits required to make the following game control flow operation atomic/correct.

* read a character

* rdloop: drain the initial terminal input before presenting the monitor prompt.
rdloop                                lda       #$04                                      ; seed A with constant $04 for the upcoming game control flow operation.
                                      lbsr      routines                                  ; run dispatch a compact file/terminal operation by function number.
                                      bcc       rdloop                                    ; continue at rdloop when the unsigned operation did not carry/borrow; this selects the next game control flow path.

* welcome the user to ROF and get monitor type
                                      lbsr      Welcome                                   ; run prompt until the player selects composite or RGB color mapping.

* set the monitor type
                                      lda       #stdout                                   ; seed A with constant stdout for the upcoming game control flow operation.
                                      ldb       #SS.Montr                                 ; seed B with constant SS.Montr for the upcoming game control flow operation.
                                      ldx       >mtype                                    ; fetch selected composite/RGB monitor type for the current game control flow decision/calculation.
                                      os9       I$SetStt                                  ; ask OS-9 to apply the selected path/device status service.

* following code section needs to open a window and get address in 68K
* get a 160x192x16 game screen using SS.AScrn
                                      lda       #stdout                                   ; seed A with constant stdout for the upcoming game control flow operation.
                                      ldb       #SS.AScrn                                 ; seed B with constant SS.AScrn for the upcoming game control flow operation.
                                      ldx       #saved_blit_y                             ; seed X with constant saved_blit_y for the upcoming game control flow operation.
                                      os9       I$SetStt                                  ; ask OS-9 to apply the selected path/device status service.
                                      lbcs      Rtn3                                      ; continue at Rtn3 when the unsigned operation carried/borrowed; this selects the next game control flow path.
                                      stx       >scrnaddr                                 ; commit constant $0002 to allocated OS-9 screen base.
                                      sty       >scrnnum                                  ; commit the computed Y value to allocated OS-9 screen number.

* save old pause/echo options then turn them off
                                      lda       #stdin                                    ; seed A with constant stdin for the upcoming game control flow operation.
                                      clrb                                                ; use zero in B as the neutral/empty value for this game control flow step.
                                      ldx       #pathopts                                 ; seed X with constant pathopts for the upcoming game control flow operation.
                                      os9       I$GetStt                                  ; ask OS-9 to query the selected path/device status service.
                                      lda       >echoflg                                  ; fetch workspace location >echoflg for the current game control flow decision/calculation.
                                      sta       >oldecho                                  ; commit workspace location >echoflg to workspace location >oldecho.
                                      lda       >pauseflg                                 ; fetch workspace location >pauseflg for the current game control flow decision/calculation.
                                      sta       >oldpause                                 ; commit workspace location >pauseflg to workspace location >oldpause.
                                      clr       >echoflg                                  ; reset workspace location >echoflg before the next game control flow phase.
                                      clr       >pauseflg                                 ; reset workspace location >pauseflg before the next game control flow phase.
                                      lda       #$01                                      ; seed A with constant $01 for the upcoming game control flow operation.
                                      clrb                                                ; use zero in B as the neutral/empty value for this game control flow step.
* NOTE!  d1 should still be set to SS.Opt here
                                      ldx       #pathopts                                 ; seed X with constant pathopts for the upcoming game control flow operation.
* NOTE!  a0 should still be set to $CCC(a6) here
                                      os9       I$SetStt                                  ; ask OS-9 to apply the selected path/device status service.


* read in the rtitle.c file into memory
                                      ldu       #ws_boot_buffer_17+$219                   ; seed U with constant ws_boot_buffer_17+$219 for the upcoming game control flow operation.
                                      leax      >rtitle,pcr                               ; advance/derive X so it addresses a field in the PCR-indexed structure for the next game control flow item.
                                      lda       #$01                                      ; seed A with constant $01 for the upcoming game control flow operation.
                                      lbsr      routines                                  ; run dispatch a compact file/terminal operation by function number.

* copy the title into actual display memory
                                      lbsr      copyscr                                   ; run RLE-expand the staged title/ship image into video memory.

* the following code needs to do a select to the new window
* now display the title on the screen
                                      ldy       >scrnnum                                  ; fetch allocated OS-9 screen number for the current game control flow decision/calculation.
                                      lda       #stdout                                   ; seed A with constant stdout for the upcoming game control flow operation.
                                      ldb       #SS.DScrn                                 ; seed B with constant SS.DScrn for the upcoming game control flow operation.
                                      os9       I$SetStt                                  ; ask OS-9 to apply the selected path/device status service.
                                      lbcs      Rtn3                                      ; continue at Rtn3 when the unsigned operation carried/borrowed; this selects the next game control flow path.

* now let's set up the palettes
                                      ldy       #ccpals                                   ; seed Y with cached 16-entry hardware palette for the upcoming game control flow operation.
                                      ldd       #$FF0F                                    ; seed D with constant $FF0F for the upcoming game control flow operation.
palloop                               sta       b,y                                       ; commit the computed A value to a field in the Y-indexed structure.
                                      decb                                                ; count down the B loop/state value to drive the next game control flow state/iteration.
                                      bpl       palloop                                   ; continue at palloop when the signed result is nonnegative; this selects the next game control flow path.

                                      leay      >pals1,pcr                                ; advance/derive Y so it addresses a field in the PCR-indexed structure for the next game control flow item.
                                      lbsr      setpal                                    ; run install a complete 16-entry palette.

                                      clr       >projection_row_workspace+$162            ; reset workspace location >projection_row_workspace+$162 before the next game control flow phase.
                                      clr       >projection_row_workspace+$163            ; reset workspace location >projection_row_workspace+$163 before the next game control flow phase.
                                      clr       >projection_row_workspace+$164            ; reset workspace location >projection_row_workspace+$164 before the next game control flow phase.
                                      clr       >projection_row_workspace+$165            ; reset workspace location >projection_row_workspace+$165 before the next game control flow phase.
                                      clr       >ws_boot_buffer_13+$174                   ; reset workspace location >ws_boot_buffer_13+$174 before the next game control flow phase.
load_ship_splash                      clr       >projection_row_workspace+$158            ; reset alternate text-row/style flag before the next game control flow phase.
                                      lda       #$07                                      ; seed A with constant $07 for the upcoming game control flow operation.
                                      sta       >projection_row_workspace+$155            ; commit constant $07 to text foreground/style nibble.
                                      ldd       #$3D9A                                    ; seed D with cockpit/message lookup field #$3D9A for the upcoming game control flow operation.
                                      std       >projection_row_workspace+$156            ; commit cockpit/message lookup field #$3D9A to current text destination/descriptor.

* read in 'rship' file
                                      ldu       #ws_boot_buffer_17+$219                   ; seed U with constant ws_boot_buffer_17+$219 for the upcoming game control flow operation.
