* loop until a joystick button is pressed (not used?)
wait_for_joystick_button              ldd       #SS.Joy                                   ; seed D with constant SS.Joy for the upcoming game control flow operation.
                                      ldx       #ws_raster_byte_01                        ; seed X with constant ws_raster_byte_01 for the upcoming game control flow operation.
                                      os9       I$GetStt                                  ; ask OS-9 to query the selected path/device status service.
                                      tsta                                                ; classify the current A value as zero, positive, or negative for the next game control flow branch.
                                      beq       wait_for_joystick_button                  ; repeat at wait_for_joystick_button when the tested state is zero/equal; this selects the next game control flow path.
                                      rts                                                 ; return to the caller with the game control flow result in registers/workspace.

* palette code
* A = color number
* B = palette position (0-15)

* writepal: update one GIME palette register only when its cached value changed.
writepal                              pshs      u,y,x,b,a                                 ; preserve u,y,x,b,a across the following game control flow work.
                                      ldx       #ccpals                                   ; seed X with cached 16-entry hardware palette for the upcoming game control flow operation.
                                      cmpa      b,x                                       ; compare the current A value with a field in cached 16-entry hardware palette; the following branch chooses the game control flow case.
                                      beq       writpal2                                  ; continue at writpal2 when the tested state is zero/equal; this selects the next game control flow path.
                                      sta       b,x                                       ; commit the computed A value to a field in cached 16-entry hardware palette.
                                      ldy       #ws_boot_buffer_20+$66A                   ; seed Y with constant ws_boot_buffer_20+$66A for the upcoming game control flow operation.
                                      sty       >palstr                                   ; commit constant $1B31 to four-byte OS-9 palette command.
                                      stb       >palstr+2                                 ; commit the computed B value to workspace location >palstr+2.
                                      sta       >palstr+3                                 ; commit the computed A value to workspace location >palstr+3.
                                      ldx       #palstr                                   ; seed X with four-byte OS-9 palette command for the upcoming game control flow operation.
                                      ldy       #saved_blit_u                             ; seed Y with constant saved_blit_u for the upcoming game control flow operation.
                                      lda       #stdout                                   ; seed A with constant stdout for the upcoming game control flow operation.
                                      os9       I$Write                                   ; ask OS-9 to write the requested bytes to the active path.

* writpal2: finish the cached palette update.
writpal2                              puls      pc,u,y,x,b,a                              ; restore u,y,x,b,a and return from this game control flow helper.


* Y = address of 16 palette entries

* setpal: install a complete 16-entry palette.
setpal                                ldb       #15                                       ; seed B with constant 15 for the upcoming game control flow operation.

* setpal2: walk the palette entries from 15 down to zero.
setpal2                               lda       b,y                                       ; fetch a field in the Y-indexed structure for the current game control flow decision/calculation.
                                      bsr       writepal                                  ; run update one GIME palette register only when its cached value changed.
                                      decb                                                ; count down the B loop/state value to drive the next game control flow state/iteration.
                                      bpl       setpal2                                   ; continue at setpal2 when the signed result is nonnegative; this selects the next game control flow path.
                                      rts                                                 ; return to the caller with the game control flow result in registers/workspace.

* copy routine:
*    X = source
*    U = destination
*    Y = bytes to copy

* copyscr: RLE-expand the staged title/ship image into video memory.
copyscr                               ldu       >scrnaddr                                 ; fetch allocated OS-9 screen base for the current game control flow decision/calculation.
                                      ldx       #ws_boot_buffer_17+$219                   ; seed X with constant ws_boot_buffer_17+$219 for the upcoming game control flow operation.
                                      lbra      rldecode                                  ; continue at expand the game's high-bit run-length encoding.


* sighand: return from an intercepted OS-9 signal.
sighand                               rti                                                 ; restore the interrupted machine frame and resume OS-9 execution.

* show welcome screen, ask for composite/rgb monitor type
* stay here until we get a legal (C/R) response

* Welcome: prompt until the player selects composite or RGB color mapping.
Welcome                               clr       >mtype                                    ; reset selected composite/RGB monitor type before the next game control flow phase.

* welcome2: print the monitor-selection prompt.
welcome2                              leax      >welcmess,pcr                             ; advance/derive X so it addresses a field in the PCR-indexed structure for the next game control flow item.
                                      ldy       #approach_x_position                      ; seed Y with constant approach_x_position for the upcoming game control flow operation.
                                      lbsr      WriteOut                                  ; run write a caller-supplied byte range to standard output.
                                      clr       >projection_row_workspace+$12E            ; reset workspace location >projection_row_workspace+$12E before the next game control flow phase.

* keyloop: poll for a valid monitor-selection key.
keyloop                               inc       >projection_row_workspace+$154            ; advance free-running prompt/random seed to drive the next game control flow state/iteration.
                                      lbsr      Rtn4                                      ; run perform a nonblocking one-character terminal read.
                                      bcs       keyloop                                   ; continue at keyloop when the unsigned operation carried/borrowed; this selects the next game control flow path.
* A = ASCII code of key pressed
                                      cmpa      #'c                                       ; compare the current A value with constant 'c; the following branch chooses the game control flow case.
                                      beq       clear_terminal_for_game                   ; continue at clear_terminal_for_game when the tested state is zero/equal; this selects the next game control flow path.
                                      cmpa      #'C                                       ; compare the current A value with constant 'C; the following branch chooses the game control flow case.
                                      beq       clear_terminal_for_game                   ; continue at clear_terminal_for_game when the tested state is zero/equal; this selects the next game control flow path.
                                      inc       >projection_row_workspace+$12E            ; advance workspace location >projection_row_workspace+$12E to drive the next game control flow state/iteration.
                                      cmpa      #'r                                       ; compare the current A value with constant 'r; the following branch chooses the game control flow case.
                                      beq       clear_terminal_for_game                   ; continue at clear_terminal_for_game when the tested state is zero/equal; this selects the next game control flow path.
                                      cmpa      #'R                                       ; compare the current A value with constant 'R; the following branch chooses the game control flow case.
                                      bne       welcome2                                  ; continue at welcome2 when the tested state is nonzero/different; this selects the next game control flow path.

clear_terminal_for_game               lbra      clearscr                                  ; continue at the internal game control flow block at clearscr.

