* initialize_screen_rows: initialize screen-row lookup tables and persistent game state.
initialize_screen_rows                ldx       #oldecho                                  ; seed X with constant oldecho for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      ldu       #saved_blit_x                             ; seed U with constant saved_blit_x for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      clra                                                ; use zero in A as the neutral/empty value for this sortie orchestration and the two-pass main frame loop step.
                                      lbsr      fill_workspace_bytes                      ; run fill a workspace range with a byte value.
                                      ldy       #screen_row_ptrs                          ; seed Y with forward scan-line pointer table for the upcoming sortie orchestration and the two-pass main frame loop operation.
begin_forward_row_table               ldb       #$C0                                      ; seed B with constant $C0 for the upcoming sortie orchestration and the two-pass main frame loop operation.
reload_screen_base                    ldx       >scrnaddr                                 ; fetch allocated OS-9 screen base for the current sortie orchestration and the two-pass main frame loop decision/calculation.

* build_forward_row_table_loop: record each forward 80-byte screen-row address.
build_forward_row_table_loop          stx       ,y++                                      ; install this scan line's base in the forward row-pointer table.
                                      leax      <$50,x                                    ; advance exactly 80 bytes to the next 160-pixel packed scan line.
                                      decb                                                ; account for one of the 192 visible scan lines.
                                      bne       build_forward_row_table_loop              ; repeat until all 192 forward row pointers are available to the rasterizer.
                                      ldy       #reverse_screen_row_ptrs                  ; maintain the 192-entry forward scan-line table used by every pixel primitive.
                                      ldb       #$60                                      ; maintain the 192-entry forward scan-line table used by every pixel primitive.
                                      ldx       #ws_boot_buffer_25+$252B                  ; maintain the 192-entry forward scan-line table used by every pixel primitive.

* build_reverse_row_table_loop: record reverse row addresses used by reflected/cockpit drawing.
build_reverse_row_table_loop          stx       ,y++                                      ; install this bottom-up scan-line address in the reverse row table.
                                      leax      <-$50,x                                   ; move one 80-byte row upward for reverse-oriented effects.
                                      decb                                                ; account for one of the 96 rows needed by the mirrored/transition drawing.
                                      bne       build_reverse_row_table_loop              ; repeat until the reverse half-screen row table is complete.
initialize_screen_bounds              ldd       >scrnaddr                                 ; fetch allocated OS-9 screen base for the current sortie orchestration and the two-pass main frame loop decision/calculation.
                                      addd      #$3C00                                    ; accumulate cockpit/message lookup field #$3C00 into allocated OS-9 screen base for the fixed-point/state update.
                                      std       >ws_boot_buffer_13+$124                   ; commit allocated OS-9 screen base to sprite/overlay drawing scratch field >ws_boot_buffer_13+$124.
                                      addd      #$0200                                    ; accumulate constant $0200 into allocated OS-9 screen base for the fixed-point/state update.
                                      std       >ws_boot_buffer_13+$126                   ; commit allocated OS-9 screen base to sprite/overlay drawing scratch field >ws_boot_buffer_13+$126.
                                      clr       >ws_boot_buffer_09+$2C                    ; reset workspace location >ws_boot_buffer_09+$2C before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_09+$2F                    ; reset workspace location >ws_boot_buffer_09+$2F before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_07+$18                    ; reset workspace location >ws_boot_buffer_07+$18 before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_07+$1C                    ; reset workspace location >ws_boot_buffer_07+$1C before the next sortie orchestration and the two-pass main frame loop phase.

* restart_game_state: restart initialization after a completed or aborted sortie.
restart_game_state                    ldx       #ws_boot_byte_03                          ; seed X with constant ws_boot_byte_03 for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      ldu       #projection_row_workspace+$159            ; seed U with packed-BCD score for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      clra                                                ; use zero in A as the neutral/empty value for this sortie orchestration and the two-pass main frame loop step.
                                      lbsr      fill_workspace_bytes                      ; run fill a workspace range with a byte value.
                                      clr       <demo_mode_flag                           ; reset attract/demo mode flag before the next sortie orchestration and the two-pass main frame loop phase.
                                      lda       #$04                                      ; seed A with constant $04 for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      sta       <current_level                            ; commit constant $04 to selected/current level number.
                                      lda       #$01                                      ; seed A with constant $01 for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      sta       <ws_frontend_byte_03                      ; commit constant $01 to workspace location <ws_frontend_byte_03.
                                      lda       #$10                                      ; seed A with constant $10 for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      sta       >projection_row_workspace+$15E            ; commit constant $10 to highest selectable/unlocked level.

* initialize_sortie_state: clear transient world, input, rescue, and animation state.
initialize_sortie_state               tst       <demo_mode_flag                           ; classify attract/demo mode flag as zero, positive, or negative for the next sortie orchestration and the two-pass main frame loop branch.
                                      bne       restart_game_state                        ; repeat at restart_game_state when the tested state is nonzero/different; this selects the next sortie orchestration and the two-pass main frame loop path.
                                      clr       <alternate_gauge_flag                     ; reset alternate cockpit drawing flag before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_09+$35                    ; reset workspace location >ws_boot_buffer_09+$35 before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       <ws_frontend_byte_10                      ; reset workspace location <ws_frontend_byte_10 before the next sortie orchestration and the two-pass main frame loop phase.
                                      ldx       #ws_boot_word_02                          ; seed X with constant ws_boot_word_02 for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      ldu       #ws_level_byte_06                         ; seed U with constant ws_level_byte_06 for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      clra                                                ; use zero in A as the neutral/empty value for this sortie orchestration and the two-pass main frame loop step.
                                      lbsr      fill_workspace_bytes                      ; run fill a workspace range with a byte value.
                                      lbsr      getjoyxy                                  ; run read the joystick and quantize both axes to -1, 0, or +1.
                                      clr       <game_started_flag                        ; reset game-started rather than attract-mode flag before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_07+$1E                    ; reset workspace location >ws_boot_buffer_07+$1E before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       <rescue_event_timer                       ; reset rescue/flight event timer before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_13+$17D                   ; reset timed palette-effect state before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_09+$12                    ; reset workspace location >ws_boot_buffer_09+$12 before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_13+$192                   ; reset pilot/Jaggi animation variant timer before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_13+$17F                   ; reset keyboard command queue read index before the next sortie orchestration and the two-pass main frame loop phase.
                                      clr       >ws_boot_buffer_13+$180                   ; reset keyboard command queue occupancy before the next sortie orchestration and the two-pass main frame loop phase.
                                      lda       #$80                                      ; seed A with constant $80 for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      sta       >ws_boot_buffer_07+$10                    ; commit constant $80 to workspace location >ws_boot_buffer_07+$10.
                                      sta       >ws_boot_buffer_07+$11                    ; commit constant $80 to workspace location >ws_boot_buffer_07+$11.
                                      sta       >ws_boot_buffer_07+$12                    ; commit constant $80 to workspace location >ws_boot_buffer_07+$12.
                                      sta       >ws_boot_buffer_07+$1F                    ; commit constant $80 to sortie initialization flag.
                                      sta       >ws_boot_buffer_07+$13                    ; commit constant $80 to workspace location >ws_boot_buffer_07+$13.
                                      sta       <animation_sentinel                       ; commit constant $80 to screen/cockpit animation sentinel.
                                      lda       #$66                                      ; seed A with constant $66 for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      sta       >ws_boot_buffer_09+$32                    ; commit constant $66 to cockpit damage color/seed.
                                      lda       #$FF                                      ; seed A with constant $FF for the upcoming sortie orchestration and the two-pass main frame loop operation.
                                      sta       <ws_main_byte_02                          ; commit constant $FF to workspace location <ws_main_byte_02.
