* plot_packed_pixel: plot one clipped four-bit pixel into a packed screen byte.
plot_packed_pixel                     pshs      a                                         ; save the X pixel coordinate while B is reused to locate its scan line.
                                      ldu       #screen_row_ptrs                          ; point U at the 192-entry forward row-address table.
                                      clra                                                ; clear the high half of the row index before doubling it into a word offset.
                                      lslb                                                ; double the row number because each scan-line pointer occupies two bytes.
                                      rola                                                ; carry the doubled row index into the high byte of D.
                                      ldu       d,u                                       ; point U at the 192-entry forward row-address table.
                                      puls      b                                         ; recover the X coordinate after resolving the destination scan line.
                                      lda       #$F0                                      ; resolve and update one packed four-bit screen pixel.
                                      lsrb                                                ; divide X by two to select its packed-pixel byte; carry remembers odd/even.
                                      bcc       mask_selected_pixel_nibble                ; keep the high-nibble mask for an even X coordinate.
                                      lda       #$0F                                      ; resolve and update one packed four-bit screen pixel.
mask_selected_pixel_nibble            anda      #$77                                      ; keep only the bit/nibble fields of the A value needed by the clipped line, span, packed-pixel, and damage drawing encoding.
                                      eora      b,u                                       ; toggle the selected packed-pixel/state bits in the A value.
                                      sta       b,u                                       ; commit the computed A value to a field in the U-indexed structure.
                                      rts                                                 ; return to the caller with the clipped line, span, packed-pixel, and damage drawing result in registers/workspace.


* store_screen_byte_at_coordinate: store one packed-pixel byte at a row/column screen coordinate.
store_screen_byte_at_coordinate       equ       *
* Stable frame after PSHS Y,B,A (offsets are from the new S):
stk_store_screen_saved_a              equ       0                                         caller's packed pixel byte
stk_store_screen_saved_b              equ       1                                         caller's packed-byte column
stk_store_screen_saved_y              equ       2                                         caller's bottom-origin Y coordinate
stk_store_screen_return               equ       4                                         caller's return address
                                      pshs      y,b,a                                     ; create a stable frame holding the caller's pixel byte, column, and Y coordinate.
                                      tfr       y,d                                       ; move the Y coordinate into D so its low byte can be converted to a row offset.
                                      pshs      b                                         ; temporarily push the original Y low byte; the named frame is one byte deeper until SUBB ,S+ pops it.
                                      ldb       #$78                                      ; choose the bottom-origin overlay boundary used to reflect Y into screen coordinates.
                                      subb      ,s+                                       ; pop the temporary Y byte and reflect it around row $78, restoring the named frame shape.
                                      lda       #$50                                      ; use the 80-byte packed-screen stride for row multiplication.
                                      mul                                                 ; convert the reflected row number into a byte offset from screen base.
                                      addd      >scrnaddr                                 ; resolve the absolute address of the requested packed screen row.
                                      tfr       d,y                                       ; use Y as the resolved destination-row pointer.
                                      lda       ,s                                        ; recover the caller's packed pixel byte from stk_store_screen_saved_a.
                                      ldb       $01,s                                     ; recover the caller's packed-byte column from stk_store_screen_saved_b.
                                      sta       b,y                                       ; write the caller's pixel byte at the caller's packed-byte column.
                                      puls      pc,y,b,a                                  ; discard the frame, restore all caller registers, and return.
